{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a constrained 2D packing problem with point-containment and area-matching requirements. I am decomposing it into a spatial partitioning/ordering task and a geometric rectangle-fitting task.",
  "helpers": [
    {
      "label": "spatial_partitioning_agent",
      "instructions": "Develop a strategy to partition the 10000x10000 grid into non-overlapping regions (e.g., using a k-d tree, quadtree, or a sweep-line based tiling) that prioritize the requested points. The output must be a set of candidate bounding boxes or Voronoi-like cells that contain exactly one requested point each, ensuring that the cells are disjoint and provide a structured layout for the second agent to refine."
    },
    {
      "label": "geometric_optimization_agent",
      "instructions": "Given a set of disjoint candidate regions and their associated target areas, perform a local optimization for each region. For each advertiser, find an axis-aligned rectangle $(x_1, y_1, x_2, y_2)$ such that the requested point $(px, py)$ is inside, the rectangle is contained within the assigned candidate region, and the area $(x_2-x_1)(y_2-y_1)$ minimizes the absolute difference $|Area_{actual} - Area_{target}|$. Ensure no two rectangles overlap by strictly adhering to the boundaries provided by the spatial partitioning agent."
    }
  ],
  "synthesis_brief": "Combine the spatial partitioning layout with the optimized rectangles. The parent agent will verify that all rectangles are within the 10000x10000 bounds, check for any accidental overlaps, and calculate the final satisfaction score based on the area error for each advertiser."
}
```

